#include <iostream>

char letterGrade(int score) {
    if (score >= 90) return 'A';
    if (score >= 80) return 'B';
    if (score >= 70) return 'C';
    if (score >= 60) return 'D';
    return 'F';
}

int main() {
    std::cout << (letterGrade(95) == 'A' ? "PASS" : "FAIL") << '\n';
    std::cout << (letterGrade(90) == 'A' ? "PASS" : "FAIL") << '\n';
    std::cout << (letterGrade(89) == 'B' ? "PASS" : "FAIL") << '\n';
    std::cout << (letterGrade(70) == 'C' ? "PASS" : "FAIL") << '\n';
    std::cout << (letterGrade(60) == 'D' ? "PASS" : "FAIL") << '\n';
    std::cout << (letterGrade(59) == 'F' ? "PASS" : "FAIL") << '\n';
    return 0;
}

